	struct TrainableEnvmap {
		std::shared_ptr<Optimizer<float>> optimizer;
		std::shared_ptr<TrainableBuffer<4, 2, float>> envmap;
		std::shared_ptr<Trainer<float, float, float>> trainer;

		ivec2 resolution;
