142			return m_density_network->padded_output_width();
143		}
144	
145		std::unique_ptr<Context> forward_impl(cudaStream_t stream, const GPUMatrixDynamic<float>& input, GPUMatrixDynamic<T>* output = nullptr, bool use_inference_params = false, bool prepare_input_gradients = false) override {
146			// Make sure our temporary buffers have the correct size for the given batch size
147			uint32_t batch_size = input.n();
148	
149			auto forward = std::make_unique<ForwardContext>();
150	
151			forward->density_network_input = GPUMatrixDynamic<T>{m_pos_encoding->padded_output_width(), batch_size, stream, m_pos_encoding->preferred_output_layout()};
152			forward->rgb_network_input = GPUMatrixDynamic<T>{m_rgb_network_input_width, batch_size, stream, m_dir_encoding->preferred_output_layout()};
153	
154			forward->pos_encoding_ctx = m_pos_encoding->forward(
155				stream,
156				input.slice_rows(0, m_pos_encoding->input_width()),
157				&forward->density_network_input,
158				use_inference_params,
159				prepare_input_gradients
160			);
161	
162			forward->density_network_output = forward->rgb_network_input.slice_rows(0, m_density_network->padded_output_width());
163			forward->density_network_ctx = m_density_network->forward(stream, forward->density_network_input, &forward->density_network_output, use_inference_params, prepare_input_gradients);
164	
165			auto dir_out = forward->rgb_network_input.slice_rows(m_density_network->padded_output_width(), m_dir_encoding->padded_output_width());
166			forward->dir_encoding_ctx = m_dir_encoding->forward(
167				stream,
168				input.slice_rows(m_dir_offset, m_dir_encoding->input_width()),
169				&dir_out,
170				use_inference_params,
171				prepare_input_gradients
172			);
173	
174			if (output) {
175				forward->rgb_network_output = GPUMatrixDynamic<T>{output->data(), m_rgb_network->padded_output_width(), batch_size, output->layout()};
176			}
177	
178			forward->rgb_network_ctx = m_rgb_network->forward(stream, forward->rgb_network_input, output ? &forward->rgb_network_output : nullptr, use_inference_params, prepare_input_gradients);
179	
180			if (output) {
181				linear_kernel(extract_density<T>, 0, stream,
182					batch_size, m_dir_encoding->preferred_output_layout() == AoS ? forward->density_network_output.stride() : 1, padded_output_width(), forward->density_network_output.data(), output->data()+3
183				);
184			}
185	
186			return forward;
187		}
188	
189		void backward_impl(
190			cudaStream_t stream,
191			const Context& ctx,
192			const GPUMatrixDynamic<float>& input,
193			const GPUMatrixDynamic<T>& output,
194			const GPUMatrixDynamic<T>& dL_doutput,
195			GPUMatrixDynamic<float>* dL_dinput = nullptr,
196			bool use_inference_params = false,
197			GradientMode param_gradients_mode = GradientMode::Overwrite
198		) override {
199			const auto& forward = dynamic_cast<const ForwardContext&>(ctx);
200	
201			// Make sure our teporary buffers have the correct size for the given batch size
202			uint32_t batch_size = input.n();
203	
204			GPUMatrix<T> dL_drgb{m_rgb_network->padded_output_width(), batch_size, stream};
205			CUDA_CHECK_THROW(cudaMemsetAsync(dL_drgb.data(), 0, dL_drgb.n_bytes(), stream));
206			linear_kernel(extract_rgb<T>, 0, stream,
207				batch_size*3, dL_drgb.m(), dL_doutput.m(), dL_doutput.data(), dL_drgb.data()
208			);
209	
210			const GPUMatrixDynamic<T> rgb_network_output{(T*)output.data(), m_rgb_network->padded_output_width(), batch_size, output.layout()};
211			GPUMatrixDynamic<T> dL_drgb_network_input{m_rgb_network_input_width, batch_size, stream, m_dir_encoding->preferred_output_layout()};
212			m_rgb_network->backward(stream, *forward.rgb_network_ctx, forward.rgb_network_input, rgb_network_output, dL_drgb, &dL_drgb_network_input, use_inference_params, param_gradients_mode);
213	
214			// Backprop through dir encoding if it is trainable or if we need input gradients
215			if (m_dir_encoding->n_params() > 0 || dL_dinput) {
216				GPUMatrixDynamic<T> dL_ddir_encoding_output = dL_drgb_network_input.slice_rows(m_density_network->padded_output_width(), m_dir_encoding->padded_output_width());
217				GPUMatrixDynamic<float> dL_ddir_encoding_input;
218				if (dL_dinput) {
219					dL_ddir_encoding_input = dL_dinput->slice_rows(m_dir_offset, m_dir_encoding->input_width());
220				}
221	
222				m_dir_encoding->backward(
223					stream,
224					*forward.dir_encoding_ctx,
225					input.slice_rows(m_dir_offset, m_dir_encoding->input_width()),
226					forward.rgb_network_input.slice_rows(m_density_network->padded_output_width(), m_dir_encoding->padded_output_width()),
227					dL_ddir_encoding_output,
228					dL_dinput ? &dL_ddir_encoding_input : nullptr,
229					use_inference_params,
230					param_gradients_mode
231				);
232			}
233	
234			GPUMatrixDynamic<T> dL_ddensity_network_output = dL_drgb_network_input.slice_rows(0, m_density_network->padded_output_width());
235			linear_kernel(add_density_gradient<T>, 0, stream,
236				batch_size,
237				dL_doutput.m(),
238				dL_doutput.data(),
239				dL_ddensity_network_output.layout() == RM ? 1 : dL_ddensity_network_output.stride(),
240				dL_ddensity_network_output.data()
241			);
242	
243			GPUMatrixDynamic<T> dL_ddensity_network_input;
244			if (m_pos_encoding->n_params() > 0 || dL_dinput) {
245				dL_ddensity_network_input = GPUMatrixDynamic<T>{m_pos_encoding->padded_output_width(), batch_size, stream, m_pos_encoding->preferred_output_layout()};
246			}
247	
248			m_density_network->backward(stream, *forward.density_network_ctx, forward.density_network_input, forward.density_network_output, dL_ddensity_network_output, dL_ddensity_network_input.data() ? &dL_ddensity_network_input : nullptr, use_inference_params, param_gradients_mode);
249	
250			// Backprop through pos encoding if it is trainable or if we need input gradients
251			if (dL_ddensity_network_input.data()) {
252				GPUMatrixDynamic<float> dL_dpos_encoding_input;
253				if (dL_dinput) {
254					dL_dpos_encoding_input = dL_dinput->slice_rows(0, m_pos_encoding->input_width());
255				}
256	
257				m_pos_encoding->backward(
258					stream,
259					*forward.pos_encoding_ctx,
260					input.slice_rows(0, m_pos_encoding->input_width()),
261					forward.density_network_input,
262					dL_ddensity_network_input,
263					dL_dinput ? &dL_dpos_encoding_input : nullptr,
264					use_inference_params,
265					param_gradients_mode
266				);
267			}
268		}
