270		void density(cudaStream_t stream, const GPUMatrixDynamic<float>& input, GPUMatrixDynamic<T>& output, bool use_inference_params = true) {
271			if (input.layout() != CM) {
272				throw std::runtime_error("NerfNetwork::density input must be in column major format.");
