476		std::string generate_device_function(const std::string& name) const override {
477			std::string density_network = name + "_density_network";
478			std::string rgb_network = name + "_rgb_network";
479			std::string pos_encoding = name + "_pos_encoding";
480			std::string dir_encoding = name + "_dir_encoding";
481	
482			std::ostringstream preamble;
483			preamble
484				<< m_density_network->generate_device_function(density_network) << "\n\n"
485				<< m_rgb_network->generate_device_function(rgb_network) << "\n\n"
486				<< m_pos_encoding->generate_device_function(pos_encoding) << "\n\n"
487				<< m_dir_encoding->generate_device_function(dir_encoding) << "\n\n"
488				;
489	
490			std::string body = dfmt(1, R"(
491					auto pos_enc_out = {POS_ENC}(input.slice<0, {POS_ENC_DIMS_IN}>(), params + {POS_ENC_PARAMS_OFFSET}, fwd_ctx ? fwd_ctx + WARP_SIZE * {POS_ENC_FWD_CTX_OFFSET} : nullptr);
492	
493					{RGB_MLP_IN} rgb_mlp_in;
494					rgb_mlp_in.slice<0, {DENSITY_MLP_DIMS_OUT}>() = {DENSITY_MLP}(pos_enc_out, params, fwd_ctx);
495					rgb_mlp_in.slice<{DENSITY_MLP_DIMS_OUT}, {DIR_ENC_DIMS_OUT}>() = {DIR_ENC}(input.slice<{DIR_OFFSET}, {DIR_ENC_DIMS_IN}>(), params + {DIR_ENC_PARAMS_OFFSET}, fwd_ctx ? fwd_ctx + WARP_SIZE * {DIR_ENC_FWD_CTX_OFFSET} : nullptr);
496	
497					auto rgb_mlp_out = {RGB_MLP}(rgb_mlp_in, params + {RGB_MLP_PARAMS_OFFSET}, fwd_ctx ? fwd_ctx + WARP_SIZE * {RGB_MLP_FWD_CTX_OFFSET} : nullptr);
498	
499					return {{rgb_mlp_out[0], rgb_mlp_out[1], rgb_mlp_out[2], rgb_mlp_in[0]}};
500				)",
501				"POS_ENC"_a = pos_encoding,
502				"POS_ENC_DIMS_IN"_a = m_pos_encoding->input_width(),
503				"POS_ENC_PARAMS_OFFSET"_a = m_density_network->n_params() + m_rgb_network->n_params(),
504				"POS_ENC_FWD_CTX_OFFSET"_a = m_density_network->device_function_fwd_ctx_bytes() + m_rgb_network->device_function_fwd_ctx_bytes(),
505				"RGB_MLP"_a = rgb_network,
506				"RGB_MLP_IN"_a = m_rgb_network->generate_vec_in(),
507				"RGB_MLP_PARAMS_OFFSET"_a = m_density_network->n_params(),
508				"RGB_MLP_FWD_CTX_OFFSET"_a = m_density_network->device_function_fwd_ctx_bytes(),
509				"DENSITY_MLP"_a = density_network,
510				"DENSITY_MLP_DIMS_OUT"_a = m_density_network->output_width(),
511				"DIR_ENC"_a = dir_encoding,
512				"DIR_ENC_DIMS_IN"_a = m_dir_encoding->input_width(),
513				"DIR_ENC_DIMS_OUT"_a = m_dir_encoding->output_width(),
514				"DIR_ENC_PARAMS_OFFSET"_a = m_density_network->n_params() + m_rgb_network->n_params() + m_pos_encoding->n_params(),
515				"DIR_ENC_FWD_CTX_OFFSET"_a = m_density_network->device_function_fwd_ctx_bytes() + m_rgb_network->device_function_fwd_ctx_bytes() + m_pos_encoding->device_function_fwd_ctx_bytes(),
516				"DIR_OFFSET"_a = m_dir_offset
517			);
518	
519			return fmt::format("{}{}", preamble.str(), this->generate_device_function_from_body(name, body));
520		}
