156	void Testbed::load_training_data(const fs::path& path) {
157		if (!path.exists()) {
158			throw std::runtime_error{fmt::format("Data path '{}' does not exist.", path.str())};
159		}
160	
161		// Automatically determine the mode from the first scene that's loaded
162		ETestbedMode scene_mode = mode_from_scene(path.str());
163		if (scene_mode == ETestbedMode::None) {
164			throw std::runtime_error{fmt::format("Unknown scene format for path '{}'.", path.str())};
165		}
166	
167		set_mode(scene_mode);
168	
169		m_data_path = path;
170	
171		switch (m_testbed_mode) {
172			case ETestbedMode::Nerf: load_nerf(path); break;
173			case ETestbedMode::Sdf: load_mesh(path); break;
174			case ETestbedMode::Image: load_image(path); break;
175			case ETestbedMode::Volume: load_volume(path); break;
176			default: throw std::runtime_error{"Invalid testbed mode."};
177		}
178	
179		m_training_data_available = true;
180	
181		update_imgui_paths();
182	}
183	
184	void Testbed::reload_training_data() {
185		if (m_data_path.exists()) {
186			load_training_data(m_data_path.str());
187		}
188	}
