195	void Testbed::set_mode(ETestbedMode mode) {
196		if (mode == m_testbed_mode) {
197			return;
198		}
199	
200		// Reset mode-specific members
201		m_image = {};
202		m_mesh = {};
203		m_nerf = {};
204		m_sdf = {};
205		m_volume = {};
206	
207		// Kill training-related things
208		m_encoding = {};
209		m_loss = {};
210		m_network = {};
211		m_nerf_network = {};
212		m_optimizer = {};
213		m_trainer = {};
214		m_envmap = {};
215		m_distortion = {};
216		m_training_data_available = false;
217	
218		// Clear device-owned data that might be mode-specific
219		for (auto&& device : m_devices) {
220			device.clear();
221		}
222	
223		// Reset paths that might be attached to the chosen mode
224		m_data_path = fs::path{};
225	
226		m_testbed_mode = mode;
227	
228		// Set various defaults depending on mode
229		if (m_testbed_mode == ETestbedMode::Nerf) {
230			if (m_devices.size() > 1) {
231				m_use_aux_devices = true;
232			}
233		} else {
234			m_use_aux_devices = false;
235		}
236	
237		if (
238			m_testbed_mode == ETestbedMode::Nerf
239		) {
240			if (m_dlss_provider && m_aperture_size == 0.0f) {
241				m_dlss = true;
242			}
243		} else {
244			m_dlss = false;
245		}
246	
247	#ifdef NGP_GUI
248		update_vr_performance_settings();
249	#endif
250	
251		reset_camera();
252	}
