254	fs::path Testbed::find_network_config(const fs::path& network_config_path) {
255		if (network_config_path.exists()) {
256			return network_config_path;
257		}
258	
259		// The following resolution steps do not work if the path is absolute. Treat it as nonexistent.
260		if (network_config_path.is_absolute()) {
261			return network_config_path;
262		}
263	
264		fs::path candidate = root_dir() / "configs" / to_string(m_testbed_mode) / network_config_path;
265		if (candidate.exists()) {
266			return candidate;
267		}
268	
269		return network_config_path;
270	}
