272	json Testbed::load_network_config(std::istream& stream, bool is_compressed) {
273		if (is_compressed) {
274			zstr::istream zstream{stream};
275			return json::from_msgpack(zstream);
276		}
277		return json::from_msgpack(stream);
278	}
279	
280	json Testbed::load_network_config(const fs::path& network_config_path) {
281		bool is_snapshot = equals_case_insensitive(network_config_path.extension(), "msgpack") ||
282			equals_case_insensitive(network_config_path.extension(), "ingp");
283		if (network_config_path.empty() || !network_config_path.exists()) {
284			throw std::runtime_error{
285				fmt::format("Network {} '{}' does not exist.", is_snapshot ? "snapshot" : "config", network_config_path.str())
286			};
287		}
288	
289		tlog::info() << "Loading network " << (is_snapshot ? "snapshot" : "config") << " from: " << network_config_path;
290	
291		json result;
292		if (is_snapshot) {
293			std::ifstream f{native_string(network_config_path), std::ios::in | std::ios::binary};
294			if (equals_case_insensitive(network_config_path.extension(), "ingp")) {
295				// zstr::ifstream applies zlib compression.
296				zstr::istream zf{f};
297				result = json::from_msgpack(zf);
298			} else {
299				result = json::from_msgpack(f);
300			}
301			// we assume parent pointers are already resolved in snapshots.
302		} else if (equals_case_insensitive(network_config_path.extension(), "json")) {
303			std::ifstream f{native_string(network_config_path)};
304			result = json::parse(f, nullptr, true, true);
305			result = merge_parent_network_config(result, network_config_path);
306		}
307	
308		return result;
309	}
310	
311	void Testbed::reload_network_from_file(const fs::path& path) {
312		if (!path.empty()) {
313			fs::path candidate = find_network_config(path);
314			if (candidate.exists() || !m_network_config_path.exists()) {
315				// Store the path _argument_ in the member variable. E.g. for the base config,
316				// it'll store `base.json`, even though the loaded config will be
317				// config/<mode>/base.json. This has the benefit of switching to the
318				// appropriate config when switching modes.
319				m_network_config_path = path;
320			}
321		}
322	
323		// If the testbed mode hasn't been decided yet, don't load a network yet, but
324		// still keep track of the requested config (see above).
325		if (m_testbed_mode == ETestbedMode::None) {
326			return;
327		}
328	
329		fs::path full_network_config_path = find_network_config(m_network_config_path);
330		bool is_snapshot = equals_case_insensitive(full_network_config_path.extension(), "msgpack");
331	
332		if (!full_network_config_path.exists()) {
333			tlog::warning() << "Network " << (is_snapshot ? "snapshot" : "config") << " path '" << full_network_config_path
334							<< "' does not exist.";
335		} else {
336			m_network_config = load_network_config(full_network_config_path);
337		}
338	
339		// Reset training if we haven't loaded a snapshot of an already trained model, in which case, presumably the network
340		// configuration changed and the user is interested in seeing how it trains from scratch.
341		if (!is_snapshot) {
342			reset_network();
343		}
344	}
345	
346	void Testbed::reload_network_from_json(const json& json, const std::string& config_base_path) {
347		// config_base_path is needed so that if the passed in json uses the 'parent' feature, we know where to look...
348		// be sure to use a filename, or if a directory, end with a trailing slash
349		m_network_config = merge_parent_network_config(json, config_base_path);
350		reset_network();
351	}
352	
353	void Testbed::load_file(const fs::path& path) {
354		if (!path.exists()) {
355			// If the path doesn't exist, but a network config can be resolved, load that.
356			if (equals_case_insensitive(path.extension(), "json") && find_network_config(path).exists()) {
357				reload_network_from_file(path);
358				return;
359			}
360	
361			tlog::error() << "File '" << path.str() << "' does not exist.";
362			return;
363		}
364	
365		if (equals_case_insensitive(path.extension(), "ingp") || equals_case_insensitive(path.extension(), "msgpack")) {
366			load_snapshot(path);
367			return;
368		}
369	
370		// If we get a json file, we need to parse it to determine its purpose.
371		if (equals_case_insensitive(path.extension(), "json")) {
372			json file;
373			{
374				std::ifstream f{native_string(path)};
375				file = json::parse(f, nullptr, true, true);
376			}
377	
